#include <stdio.h>
#include <stdlib.h>

struct Node {
    int data;
    struct Node* next;
};

/* Insert a new node at the beginning of the list */
void insertAtHead(struct Node** headRef, int val) {
    struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));
    if (newNode == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(EXIT_FAILURE);
    }
    newNode->data = val;
    newNode->next = *headRef;
    *headRef = newNode;
}

/* Delete the first node with the specified key value */
void deleteNode(struct Node** headRef, int key) {
    struct Node* temp = *headRef;
    struct Node* prev = NULL;

    /* Handle case where head itself holds the key */
    if (temp != NULL && temp->data == key) {
        *headRef = temp->next;
        free(temp);
        return;
    }

    /* Search for key while keeping track of previous node */
    while (temp != NULL && temp->data != key) {
        prev = temp;
        temp = temp->next;
    }

    /* If key is not present in the list */
    if (temp == NULL) {
        printf("Key %d not found in list.\n", key);
        return;
    }

    /* Unlink the node from the linked list */
    prev->next = temp->next;
    free(temp);
}

/* Print the complete list sequential values */
void printList(struct Node* node) {
    while (node != NULL) {
        printf("%d -> ", node->data);
        node = node->next;
    }
    printf("NULL\n");
}

/* Deallocate all list nodes to prevent memory leak */
void freeList(struct Node* head) {
    struct Node* temp;
    while (head != NULL) {
        temp = head;
        head = head->next;
        free(temp);
    }
}

int main() {
    struct Node* head = NULL;

    insertAtHead(&head, 30);
    insertAtHead(&head, 20);
    insertAtHead(&head, 10);

    printf("Initial List: ");
    printList(head);

    printf("Deleting 20...\n");
    deleteNode(&head, 20);
    printList(head);

    freeList(head);
    return 0;
}

