#include <stdio.h>
#include <stdlib.h>

struct BSTNode {
    int data;
    struct BSTNode* left;
    struct BSTNode* right;
};

/* Function to create a new BST node */
struct BSTNode* createNode(int value) {
    struct BSTNode* newNode = (struct BSTNode*)malloc(sizeof(struct BSTNode));
    if (newNode == NULL) {
        fprintf(stderr, "Out of memory!\n");
        exit(EXIT_FAILURE);
    }
    newNode->data = value;
    newNode->left = NULL;
    newNode->right = NULL;
    return newNode;
}

/* Recursive function to insert a key in the BST */
struct BSTNode* insert(struct BSTNode* root, int value) {
    if (root == NULL) {
        return createNode(value);
    }

    if (value < root->data) {
        root->left = insert(root->left, value);
    } else if (value > root->data) {
        root->right = insert(root->right, value);
    }
    /* Duplicate values are ignored in this implementation */
    return root;
}

/* Recursive In-order Traversal (Left, Root, Right) */
void inorderTraversal(struct BSTNode* root) {
    if (root != NULL) {
        inorderTraversal(root->left);
        printf("%d ", root->data);
        inorderTraversal(root->right);
    }
}

/* Search for a value in the BST */
struct BSTNode* search(struct BSTNode* root, int key) {
    if (root == NULL || root->data == key) {
        return root;
    }
    if (key < root->data) {
        return search(root->left, key);
    }
    return search(root->right, key);
}

/* Helper to deallocate tree memory */
void freeTree(struct BSTNode* root) {
    if (root != NULL) {
        freeTree(root->left);
        freeTree(root->right);
        free(root);
    }
}

int main() {
    struct BSTNode* root = NULL;

    /* Insert elements to form a BST */
    root = insert(root, 50);
    insert(root, 30);
    insert(root, 70);
    insert(root, 20);
    insert(root, 40);

    printf("In-order traversal: ");
    inorderTraversal(root);
    printf("\n");

    int key = 30;
    struct BSTNode* result = search(root, key);
    if (result != NULL) {
        printf("Element %d found in BST.\n", key);
    } else {
        printf("Element %d not found in BST.\n", key);
    }

    freeTree(root);
    return 0;
}

