void reverseList(struct Node** headRef) {
    struct Node* prev = NULL;
    struct Node* current = *headRef;
    struct Node* next = NULL;
    while (current != NULL) {
        next = current->next;  /* Save next node */
        current->next = prev;  /* Reverse current node's pointer */
        prev = current;        /* Move prev one step forward */
        current = next;        /* Move current one step forward */
    }
    *headRef = prev;           /* Update the head pointer */
}

#include <stdio.h>
#include <stdlib.h>

struct StackNode {
    int data;
    struct StackNode* next;
};

void push(struct StackNode** top, int val) {
    struct StackNode* newNode = (struct StackNode*)malloc(sizeof(struct StackNode));
    if (!newNode) return;
    newNode->data = val;
    newNode->next = *top;
    *top = newNode;
}

int pop(struct StackNode** top) {
    if (*top == NULL) return -1; /* Stack underflow sentinel */
    struct StackNode* temp = *top;
    int popped = temp->data;
    *top = temp->next;
    free(temp);
    return popped;
}

int hasCycle(struct Node* head) {
    struct Node* slow = head;
    struct Node* fast = head;
    while (fast != NULL && fast->next != NULL) {
        slow = slow->next;          /* Move slow pointer by 1 */
        fast = fast->next->next;    /* Move fast pointer by 2 */
        if (slow == fast) {
            return 1;               /* Cycle detected */
        }
    }
    return 0;                       /* No cycle found */
}

struct BSTNode* findLCA(struct BSTNode* root, int n1, int n2) {
    while (root != NULL) {
        /* If both n1 and n2 are smaller than root, LCA is in left subtree */
        if (root->data > n1 && root->data > n2) {
            root = root->left;
        }
        /* If both n1 and n2 are greater than root, LCA is in right subtree */
        else if (root->data < n1 && root->data < n2) {
            root = root->right;
        }
        /* If one is smaller and the other is larger, this node is the LCA */
        else {
            break;
        }
    }
    return root;
}

